@module arrangePage  src=arrangePage.lua  loc=874  sha=e90785c  mode=chunk
@deps cm, cmgr, chrome, gui, onDive

# Invariants & contracts
  @invariant  render-only — cursor + scroll + focus live in av (module-locals); track list + slot palette come from am, which reads cm/REAPER fresh each query. Page holds no persistent state of its own.
  @invariant  arrange page is project-wide — bind() takes no take and never re-keys cm; the tracker take and the sampler track are unaffected by switching to / from arrange.
  @invariant  cursor-nav commands live in cmgr:scope('arrange'); coord pushes the scope on activation. Names overlap with the tracker scope's arrow commands but scopes don't stack — only one is active at a time.
  @invariant  body splits horizontally into a grid pane (variable width) and a fixed-width palette pane (PALETTE_W). The palette shows slots for the focused track, i.e. the track under av:cursorCol() — no separate "focused track" pointer.

# Shapes
  @shape  press = { qn, take, mode = 'move'|'resizeEnd', duplicate, moved } — mouse-down snapshot, nil when no button is down over the grid; `moved` flips once ImGui's drag threshold is crossed.

# Imports
  @require util = 'util'  @ 9
  @require ImGui = 'imgui'  @ 15

# Constructed sub-instances
  @construct am = util.instantiate('arrangeManager')  @ 26
  @construct av = util.instantiate('arrangeView')  @ 27

# Private state
  @state ctx = gui and gui.ctx or nil  @ 20
      @contract  owns the arrange substack: builds am and av internally; coord passes primitives (cm, cmgr, chrome, gui) and the onDive callback (routes a MIDI take into the tracker page).
  @state monoFont = gui and gui.font or nil  @ 23
  @state uiSize = gui and gui.fontSize and gui.fontSize.ui or 12  @ 24
  @state ap = {}  @ 29
  @state PALETTE_W = 200  @ 31
  @state PANE_GAP = 11  @ 34
  @state QN_W, TRACK_W = 32, 72  @ 35
  @state GUTTER_PAD = 8  @ 39
  @state SLOT_KEY_W, SLOT_KIND_W = 18, 16  @ 41
  @state MODAL_TITLE = 'arrange modal'  @ 55
  @state modal = nil  @ 56   -- { kind, ... } | nil
  @state modalFocus = false  @ 57
  @state modalOpenAtFrameStart = false  @ 58
  @state press = nil  @ 62
      @invariant  mouse drag relocates a take freely, not gap-bounded like the keyboard nudge — the candidate is validated by am:rangeIsClear against every other take, so a drag may carry a take past a neighbour into any clear space. The moved edge snaps to a row box unless Shift is held; Alt at mouse-down duplicates instead of moving. Every press moves the cursor to the clicked cell. A press that never crosses the drag threshold is also a focus click: it focuses the take under the press, or clears focus if the press was on empty space.
  @state DRAG_EDGE_PX = 5  @ 63
  @state GHOST_BLOCKED  @ 64   -- lazy: blocked-drag ghost colour
  @state SLOT_FILL_ALPHA = 0.85  @ 102
  @state SLOT_BORDER_ALPHA = 0.75  @ 103
  @state slotColourCache = {}  @ 104
  @state ORPHAN  @ 105   -- lazy { fill, border, focusFill, focusBorder }
  @state HEADER_PAD = 8  @ 144
  @state HEADER_GAP = 4  @ 145
  @state CREATE_DEFAULT_ROWS = 4  @ 502
  @state arrange = cmgr:scope('arrange')  @ 767
      @invariant  arrange-scope cursor-nav: arrow keys move cursor by 1 row / 1 col. Negative coords clamp in av; upper-bound clamping belongs to the page once it knows project size (deferred — phase 4+ adds Home/End/PgUp/PgDn that need real bounds).
      @invariant  62 place commands (drop0..dropZ) sit in cmgr:scope('arrange'), one per base62 slot. Pressing a key with no slot defined at that index is a silent no-op (am:dropInstance returns nil). The drop inherits the slot's existing-instance length — a real snap selector lands with the toolbar.
      @invariant  createSlot (Ctrl+Enter) opens the create modal — the *only* slot-minting gesture. Slots have no existence apart from items on the grid; rename/delete buttons in the palette act on existing slots.
  @state placeCmds, placeBinds = {}, {}  @ 865

# Private functions
  -- Style + draw helpers
  @fn pushBodyStyles()  @ 68
  @fn popBodyStyles()  @ 76
